from __future__ import annotations

import sys
from pathlib import Path

sys.path.append(str(Path(__file__).resolve().parents[1]))

from app.integrations.hera import HeraClient


def test_hera_poll_prefers_successful_output_over_lagging_top_level_status() -> None:
    client = HeraClient(api_key="test", base_url="https://api.hera.video/v1")

    payload = {
        "status": "in-progress",
        "outputs": [
            {
                "status": "success",
                "file_url": "https://cdn.hera.video/example.mp4",
                "error": None,
            }
        ],
    }

    top_level_status = str(payload.get("status", "")).lower()
    outputs = payload.get("outputs") or []
    status = top_level_status
    file_url: str | None = None
    error: str | None = None
    if isinstance(outputs, list) and outputs:
        first = outputs[0]
        if isinstance(first, dict):
            output_status = str(first.get("status", "")).lower()
            if isinstance(first.get("file_url"), str):
                file_url = first["file_url"]
            if isinstance(first.get("error"), str):
                error = first["error"]
            if output_status == "success" and file_url:
                status = "success"
            elif output_status == "failed":
                status = "failed"
            elif top_level_status not in {"success", "failed"} and output_status == "in-progress":
                status = "in-progress"

    assert client is not None
    assert status == "success"
    assert file_url == "https://cdn.hera.video/example.mp4"
    assert error is None

